class OAuth2Client {
  constructor(clientId, redirectUri) {
    this.clientId = clientId;
    this.redirectUri = redirectUri;
    this.token = null;
  }

  authorize() {
    const authUrl = `https://authorization-server.com/oauth/authorize?response_type=token&client_id=${this.clientId}&redirect_uri=${encodeURIComponent(this.redirectUri)}&scope=read%20write`;
    window.location.href = authUrl;
  }

  handleCallback() {
    if (window.location.hash.includes('access_token')) {
      const urlParams = new URLSearchParams(window.location.hash.substring(1));
      this.token = urlParams.get('access_token');
      localStorage.setItem('oauthToken', this.token);
      window.history.replaceState({}, document.title, '/');
    } else {
      console.error('No access token found in the callback URL.');
    }
  }

  getToken() {
    if (!this.token) {
      this.token = localStorage.getItem('oauthToken');
    }
    return this.token;
  }

  async makeApiCall(url, method = 'GET', data = null) {
    const token = this.getToken();
    if (!token) {
      console.error('No access token available.');
      return null;
    }

    const headers = new Headers({
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    });

    const options = {
      method,
      headers,
      body: data ? JSON.stringify(data) : null
    };

    try {
      const response = await fetch(url, options);
      if (!response.ok) {
        throw new Error(`API call failed with status ${response.status}`);
      }
      return await response.json();
    } catch (error) {
      console.error('Error making API call:', error);
      return null;
    }
  }
}

